import{_ as i,o as n,c as t,ae as a}from"./chunks/framework.CyZiF_rV.js";const m=JSON.parse('{"title":"KSeF API 2.0 – Overview of Key Changes","description":"","frontmatter":{},"headers":[],"relativePath":"en/przeglad-kluczowych-zmian-ksef-api-2-0.md","filePath":"en/przeglad-kluczowych-zmian-ksef-api-2-0.md"}'),o={name:"en/przeglad-kluczowych-zmian-ksef-api-2-0.md"};function s(r,e,l,c,p,d){return n(),t("div",null,[...e[0]||(e[0]=[a('<blockquote><p><strong>Translation.</strong> Original: <a href="https://github.com/CIRFMF/ksef-docs/blob/main/przeglad-kluczowych-zmian-ksef-api-2-0.md" target="_blank" rel="noreferrer">przeglad-kluczowych-zmian-ksef-api-2-0.md</a></p></blockquote><h1 id="ksef-api-2-0-–-overview-of-key-changes" tabindex="-1">KSeF API 2.0 – Overview of Key Changes <a class="header-anchor" href="#ksef-api-2-0-–-overview-of-key-changes" aria-label="Permalink to &quot;KSeF API 2.0 – Overview of Key Changes&quot;">​</a></h1><p>09.06.2025</p><h1 id="introduction" tabindex="-1">Introduction <a class="header-anchor" href="#introduction" aria-label="Permalink to &quot;Introduction&quot;">​</a></h1><p>This document is addressed to technical teams and developers with experience in KSeF API version 1.0. It contains an overview of the most important changes introduced in version 2.0, along with a discussion of new capabilities and practical integration improvements.</p><p>The purpose of this document is to:</p><ul><li>Identify the main differences compared to version 1.0</li><li>Present the benefits of migrating to version 2.0</li><li>Facilitate preparation of integrations for system requirements implemented on February 1, 2026</li></ul><hr><h2 id="documentation-and-tools-supporting-integration-with-ksef-api-2-0" tabindex="-1">Documentation and tools supporting integration with KSeF API 2.0 <a class="header-anchor" href="#documentation-and-tools-supporting-integration-with-ksef-api-2-0" aria-label="Permalink to &quot;Documentation and tools supporting integration with KSeF API 2.0&quot;">​</a></h2><p>To facilitate the transition to the new API version and ensure proper implementation, a set of official materials and tools supporting integrators has been made available:</p><p><strong>Technical documentation (OpenAPI)</strong></p><p>KSeF API version 2.0 has been described in the OpenAPI standard, which enables both easy browsing of documentation by developers and automatic generation of integration code.</p><ul><li><p><strong>Documentation</strong> (interactive online version):<br> Browser interface in the form of a web page, presenting descriptions of API methods, data models, parameters and usage examples. Intended for developers and integration analysts: [<a href="https://api-test.ksef.mf.gov.pl/docs/v2/index.html" target="_blank" rel="noreferrer">link</a>].</p></li><li><p><strong>Specification</strong> (OpenAPI JSON file):<br> Raw OpenAPI specification file in JSON format, intended for use in tools automating integration (e.g., code generators, API contract validators): [<a href="https://api-test.ksef.mf.gov.pl/docs/v2/openapi.json" target="_blank" rel="noreferrer">link</a>].</p></li></ul><p><strong>Official KSeF 2.0 Client integration library (open source)</strong></p><p>Public library made available on an open source basis, developed in parallel with subsequent API versions and maintained in full compliance with the specification. It constitutes the recommended integration tool, enabling current tracking of changes and reducing the risk of incompatibility with current system releases.</p><ul><li><p><strong>C#:</strong> [<a href="https://github.com/CIRFMF/ksef-client-csharp" target="_blank" rel="noreferrer">link</a>]</p></li><li><p><strong>Java:</strong> [<a href="https://github.com/CIRFMF/ksef-client-java" target="_blank" rel="noreferrer">link</a>]</p></li></ul><p><strong>Published packages</strong></p><p>The KSeF 2.0 Client library will be available in official package repositories for the most popular programming languages. For the .NET platform, it will be published as a NuGet package, while for the Java environment – as a Maven Central artifact. Publishing in these repositories will enable easy inclusion of the library in projects and automatic tracking of updates compatible with subsequent API versions.</p><p><strong>Step-by-step guide</strong></p><ul><li><strong>Integration guide / tutorial:</strong><br> Practical step-by-step instructions along with code fragments illustrating how to use key system endpoints. <br>[<a href="https://github.com/CIRFMF/ksef-docs" target="_blank" rel="noreferrer">link</a>]</li></ul><h1 id="key-changes-in-api-2-0" tabindex="-1">Key Changes in API 2.0 <a class="header-anchor" href="#key-changes-in-api-2-0" aria-label="Permalink to &quot;Key Changes in API 2.0&quot;">​</a></h1><h2 id="new-jwt-based-authentication-model" tabindex="-1">New JWT-based authentication model <a class="header-anchor" href="#new-jwt-based-authentication-model" aria-label="Permalink to &quot;New JWT-based authentication model&quot;">​</a></h2><p>In version 1.0, authentication was tightly coupled with opening an interactive session, which introduced many limitations and complicated integration.</p><p>In version 2.0:</p><ul><li><p>Authentication has been <strong>separated as an independent process</strong>, independent of session initialization.</p></li><li><p><strong>Standard JWT tokens</strong> have been introduced, which are used to authorize all protected operations.</p></li></ul><p>Benefits:</p><ul><li>compliance with market practices,</li><li>ability to reuse tokens to create multiple sessions,</li><li><strong>support for token refresh and revocation</strong>.</li></ul><p>Authentication process details: [<a href="https://github.com/CIRFMF/ksef-docs/blob/main/uwierzytelnianie.md" target="_blank" rel="noreferrer">link</a>]</p><h2 id="unified-initialization-process-for-batch-and-interactive-sessions" tabindex="-1">Unified initialization process for batch and interactive sessions <a class="header-anchor" href="#unified-initialization-process-for-batch-and-interactive-sessions" aria-label="Permalink to &quot;Unified initialization process for batch and interactive sessions&quot;">​</a></h2><p>In API 2.0, the session opening process has been unified and made independent of the operating mode. After obtaining an authentication token, you can open both an interactive session: POST /sessions/online, and a batch session: POST /sessions/batch.</p><p>In both cases, a simple JSON is passed containing:</p><ul><li><p>form code (formCode),</p></li><li><p>encrypted AES key for encrypting invoice data (encryptionKey).</p></li></ul><p>In the case of batch sending, a list of partial files along with metadata included in the package is also passed.</p><p>Details and usage examples:</p><ul><li>interactive sending [<a href="https://github.com/CIRFMF/ksef-docs/blob/main/sesja-interaktywna.md" target="_blank" rel="noreferrer">link</a>]</li><li>batch sending [<a href="https://github.com/CIRFMF/ksef-docs/blob/main/sesja-wsadowa.md" target="_blank" rel="noreferrer">link</a>]</li></ul><h2 id="mandatory-encryption-of-all-invoices" tabindex="-1">Mandatory encryption of all invoices <a class="header-anchor" href="#mandatory-encryption-of-all-invoices" aria-label="Permalink to &quot;Mandatory encryption of all invoices&quot;">​</a></h2><p>In version 1.0, invoice encryption was mandatory only in batch mode. In interactive mode, the ability to encrypt existed, but was optional.</p><p>In version 2.0, encryption of all invoices – both in batch and interactive mode – <strong>is required</strong>.</p><p>Each invoice or package of invoices must be encrypted locally by the client using an <strong>AES key</strong>, which:</p><ul><li><p>is generated individually for each session,</p></li><li><p>passed to the system during session opening (encryptionKey).</p></li></ul><h2 id="asymmetric-encryption" tabindex="-1">Asymmetric encryption <a class="header-anchor" href="#asymmetric-encryption" aria-label="Permalink to &quot;Asymmetric encryption&quot;">​</a></h2><p>In version 2.0, <code>RSA-OAEP</code> with <code>SHA-256</code> and <code>MGF1-SHA256</code> has been introduced. Encryption of KSeF tokens is performed with a separate key from the encryption of the symmetric key used for invoices.</p><p>Current <strong>public key certificates</strong> are returned by the public endpoint: GET <code>/security/public-key-certificates</code></p><h2 id="consistency-and-new-naming-convention-in-api-2-0" tabindex="-1">Consistency and new naming convention in API 2.0 <a class="header-anchor" href="#consistency-and-new-naming-convention-in-api-2-0" aria-label="Permalink to &quot;Consistency and new naming convention in API 2.0&quot;">​</a></h2><p>One of the key changes in KSeF API 2.0 is the unification and simplification of the naming convention for resources, parameters, and JSON models. In version 1.0, the API contained a number of inconsistencies and excessive complexity resulting from system evolution.</p><p>In version 2.0:</p><ul><li><p><strong>Endpoints</strong> gained readable, REST-ful naming (e.g., sessions/online, auth/token, permissions/entities/grants).</p></li><li><p><strong>Operation names</strong> have been simplified and reflect the actual action (e.g., grant, revoke, refresh).</p></li><li><p>The structure of <strong>headers, parameters, and data formats</strong> has been organized to be consistent and compliant with REST API design best practices.</p></li><li><p><strong>Data structures</strong> are flat and clear – identifier and permission types have explicitly defined enum types (Nip, Pesel, Fingerprint), without the need to analyze subtypes.</p></li></ul><p>Changes in version 2.0 also include updates to names and data structures. Although a complete map of these changes has not been presented in this document, it is available in the OpenAPI v2 documentation and in code examples in the official GitHub repository.</p><p>It should be emphasized that the changes are not drastic in nature – they <strong>do not affect</strong> the general logic of the KSeF system operation, but only organize and simplify naming and structures, making the API more transparent and intuitive to use.</p><p>Migration to version 2.0 should be treated as a change in integration contract and requires adaptation of implementation on the side of external systems. It is recommended to use the official integration library <strong>KSeF 2.0 Client</strong>, developed and maintained by the team responsible for the API. This library implements all available endpoints and data models, which significantly facilitates the migration process and provides stable support also in future system versions.</p><h2 id="new-module-for-managing-internal-certificates" tabindex="-1">New module for managing internal certificates <a class="header-anchor" href="#new-module-for-managing-internal-certificates" aria-label="Permalink to &quot;New module for managing internal certificates&quot;">​</a></h2><p>As part of KSeF API version 2.0, mechanisms have been introduced enabling the issuance and management of internal <strong>KSeF certificates</strong> [link to documentation]. The certificates will enable authentication in KSeF and are necessary for issuing invoices in offline mode [link to documentation].</p><p>Entities that successfully complete the authentication process will be able to:</p><ul><li><p>submit an application for issuing an internal KSeF certificate, containing selected attributes from the signature certificate used during authentication,</p></li><li><p>download the issued certificate in digital form,</p></li><li><p>check the status of a submitted certificate issuance application,</p></li><li><p>download a list of metadata for issued certificates,</p></li><li><p>check the available certificate limit.</p></li></ul><h2 id="batch-sending-process-improvement" tabindex="-1">Batch sending process improvement <a class="header-anchor" href="#batch-sending-process-improvement" aria-label="Permalink to &quot;Batch sending process improvement&quot;">​</a></h2><p>In KSeF API version 2.0, a significant improvement has been introduced in the area of batch session processing. The previous solution available in API 1.0 was inefficient – if even one invoice in a package contained an error, the entire shipment was rejected. This approach effectively limited the use of batch mode by integrators and caused significant operational difficulties.</p><p>In the new solution, when sending a package of documents:</p><ul><li><p>each invoice is processed independently,</p></li><li><p>any errors affect only specific invoices, not the entire shipment,</p></li><li><p>the number of erroneous invoices is returned for the session status,</p></li><li><p>a dedicated endpoint is available that allows downloading the detailed status of incorrectly processed invoices along with information about any errors.</p></li></ul><p>This change significantly improves the reliability and efficiency of batch mode and is based on the same package sending model without the risk of losing the entire package due to individual errors.</p><h2 id="invoice-duplicate-verification" tabindex="-1">Invoice duplicate verification <a class="header-anchor" href="#invoice-duplicate-verification" aria-label="Permalink to &quot;Invoice duplicate verification&quot;">​</a></h2><p>The method of detecting duplicates has been changed – business data of the invoice is now checked (Podmiot1:NIP, RodzajFaktury, P_2), not the file hash. Details – <a href="./faktury/weryfikacja-faktury.html">Invoice verification</a>.</p><h2 id="changes-in-the-permissions-module" tabindex="-1">Changes in the Permissions module <a class="header-anchor" href="#changes-in-the-permissions-module" aria-label="Permalink to &quot;Changes in the Permissions module&quot;">​</a></h2><p>Changes in the permissions module involve changing some aspects of their functioning logic in KSeF 2.0.</p><p>In response to reported comments, version 2.0 of the system introduced a mechanism for granting permissions indirectly, which replaces the previous principle of inheriting permissions to view and issue invoices. The new interface enables separation of viewing client (partner) invoices and the ability to issue invoices on their behalf from viewing invoices and issuing own invoices of the entity (e.g., accounting office).</p><p>The mechanism consists of granting an entity permission by the client to view or issue invoices with a special option enabled that allows further transfer of this permission by the authorized entity. After receiving such permission, the entity can grant it, for example, to its employees. After performing these actions, these employees will be able to service the indicated client within the scope specified by the granted permissions.</p><p>It is also possible for an entity to grant so-called general permissions, which allow an employee authorized in this way to service all clients of the entity – of course, to the extent that these clients have authorized this entity and taking into account the scope of the employee&#39;s permissions (to view and/or issue invoices).</p><p>Thanks to this mechanism, granting and functioning of permissions to view and issue invoices within the entity itself are not linked to permissions to handle client invoices. This gives entities better possibilities for profiling employee permissions than the previously functioning inheritance mechanism in KSeF. It was based on granting employees permissions to view and issue invoices within the entity, and if the entity had appropriate permissions from clients, these permissions automatically passed to employees (were inherited). As a result – an employee could only serve clients when they simultaneously had the right to view and/or issue entity invoices. And this was often an excessive permission, which could cause problems in organizations.</p><p>Additionally, the system introduced a new type of permission and new login capabilities, which enables handling of self-billing by EU entities. It is now possible to log in in a context defined by a Polish entity (identified by NIP) and an EU country entity identified by the VAT number of the EU country. In such a defined context, it is possible for authenticated representatives of the indicated EU entity to issue invoices in self-billing mode on behalf of the indicated Polish entity.</p><p>Within the API definition, all permissions have been organized into logical groups corresponding to individual functional areas of the system.</p><h2 id="api-call-limits-rate-limiting" tabindex="-1">API call limits (rate limiting) <a class="header-anchor" href="#api-call-limits-rate-limiting" aria-label="Permalink to &quot;API call limits (rate limiting)&quot;">​</a></h2><p>In KSeF API version 2.0, a precise and predictable call limit mechanism (rate limits) has been introduced, which replaces the previous solutions known from version 1.0. Each endpoint in the system is subject to a limit on the number of requests in given time intervals: per second, minute, hour.</p><p>The ranges and values of limits are:</p><ul><li>publicly available: <a href="./limity/limity-api.html">API limits</a>,</li><li>differentiated depending on the environment (test environment has less restrictive limits than production),</li><li>adapted to the nature of operations: <ul><li>for protected endpoints – limits are applied per context and IP address,</li><li>for open endpoints – limits are applied per IP address.</li></ul></li></ul><p>The new limit model has been designed so as not to restrict typical testing of applications integrating with the system. This solution provides greater transparency, predictability, and better system resilience, both in test and production environments.</p><h2 id="auxiliary-api-for-generating-test-data-test-environment" tabindex="-1">Auxiliary API for generating test data (test environment) <a class="header-anchor" href="#auxiliary-api-for-generating-test-data-test-environment" aria-label="Permalink to &quot;Auxiliary API for generating test data (test environment)&quot;">​</a></h2><p>In the KSeF API 2.0 test environment, a dedicated <strong>auxiliary API for generating test data</strong> will be made available, enabling quick creation of companies, organizational structures, and contexts necessary for conducting integration tests.</p><p>Thanks to this solution, it will be possible, among others:</p><ul><li><p><strong>simulate the establishment of a new business entity</strong>,</p></li><li><p><strong>simulate granting permissions by ZAW-FA</strong>,</p></li><li><p><strong>create units within the JST structure</strong>,</p></li><li><p>create tax <strong>VAT groups</strong> (GVAT) along with related entities,</p></li><li><p><strong>define enforcement bodies</strong> <strong>and bailiffs</strong>.</p></li></ul><p>Normally, the process of registering companies and granting permissions for real entities in the production environment requires formal actions (e.g., visits to the tax office). In the test environment, such data does not exist. Therefore, the <strong>auxiliary API is an essential tool</strong>, enabling integrators to independently create test entities on which they can freely implement and verify complete scenarios of their application operation.</p>',79)])])}const u=i(o,[["render",s]]);export{m as __pageData,u as default};
